document.getElementById('loginForm').addEventListener('submit', function(e) {
    e.preventDefault();

    // Dynamically retrieve the absolute path generated by Django
    const loginUrl = this.getAttribute('data-login-url'); 
    const formData = new FormData(this);
    
    fetch(loginUrl, { // Use the variable here
        method: 'POST',
        body: formData,
        headers: {
            'X-Requested-With': 'XMLHttpRequest'
        }
    })
    .then(response => response.json().then(data => ({ status: response.status, body: data })))
    .then(res => {
        if (res.body.success) {
            window.location.href = res.body.redirect_url;
        } else {
            showDynamicToast(res.body.error_message);
        }
    })
    .catch(error => {
        console.error('Error:', error);
        showDynamicToast('An unexpected error occurred. Please try again.');
    });
});

function showDynamicToast(message) {
    const container = document.getElementById('toastContainer');
    const template = document.getElementById('jsToastTemplate');
    if (!container || !template) return;

    // 1. Clone the template blueprint structure
    const clone = template.content.cloneNode(true);
    const toastId = 'toast-js-' + Date.now();

    // 2. Safely populate the dynamic parts
    const checkbox = clone.querySelector('.toast-state');
    const closeBtn = clone.querySelector('.close-btn');
    const description = clone.querySelector('.toast-desc');

    checkbox.id = toastId;
    closeBtn.setAttribute('for', toastId);
    description.textContent = message; // Safe text insertion prevents XSS vulnerabilities

    // 3. Append the populated clone into your wrapper container
    container.appendChild(clone);

    // 4. Memory cleanup after animation finishes (6 seconds)
    const newToastItem = container.lastElementChild;
    setTimeout(() => {
        if (newToastItem && newToastItem.parentNode) {
            newToastItem.remove();
        }
    }, 6000);
}
